// Deepfake-/Manipulations-Check via Sightengine. Bild als oeffentliche URL ODER hochgeladene data-URL (Multipart).
async function run(input) {
  const apiUser = String((input && input.apiUser) || '').trim();
  const apiSecret = String((input && input.apiSecret) || '').trim();
  if (!apiUser || !apiSecret) return { fehler: 'Sightengine api_user und api_secret noetig (Gratis-Tier auf sightengine.com).' };
  const imageData = String((input && input.imageData) || '').trim();
  const imageUrl = String((input && input.imageUrl) || '').trim();
  let d;
  try {
    let res;
    if (imageData) {
      const m = imageData.match(/^data:(image\/[a-z0-9.+-]+);base64,(.+)$/i);
      if (!m) return { fehler: 'Ungueltiges Bildformat — erwartet data:image/...;base64,...' };
      const bin = atob(m[2]);
      const arr = new Uint8Array(bin.length);
      for (let i = 0; i < bin.length; i++) arr[i] = bin.charCodeAt(i);
      const fd = new FormData();
      fd.append('media', new Blob([arr], { type: m[1] }), 'image');
      fd.append('models', 'deepfake,genai');
      fd.append('api_user', apiUser);
      fd.append('api_secret', apiSecret);
      res = await fetch('https://api.sightengine.com/1.0/check.json', { method: 'POST', body: fd });
    } else if (/^https?:\/\//.test(imageUrl)) {
      const ep = 'https://api.sightengine.com/1.0/check.json?models=deepfake,genai'
        + '&api_user=' + encodeURIComponent(apiUser) + '&api_secret=' + encodeURIComponent(apiSecret)
        + '&url=' + encodeURIComponent(imageUrl);
      res = await fetch(ep);
    } else {
      return { fehler: 'Bitte imageUrl (oeffentliche URL) oder imageData (hochgeladenes Bild als data-URL) angeben.' };
    }
    if (!res.ok) return { fehler: 'Sightengine HTTP ' + res.status + ' — Schluessel oder Kontingent pruefen.' };
    d = await res.json();
  } catch (e) {
    return { fehler: 'Sightengine nicht erreichbar (Zeitueberschreitung oder Netzwerkfehler).' };
  }
  if (!d || d.status !== 'success') return { fehler: (d && d.error && d.error.message) || 'Pruefung fehlgeschlagen.' };
  const deepfake = (d.type && typeof d.type.deepfake === 'number') ? d.type.deepfake : 0;
  const aiGen = (d.type && typeof d.type.ai_generated === 'number') ? d.type.ai_generated : 0;
  const score = Math.max(deepfake, aiGen);
  function stufe(s) {
    if (s < 0.2) return 'sehr wahrscheinlich echt';
    if (s < 0.5) return 'unklar';
    if (s < 0.8) return 'wahrscheinlich manipuliert';
    return 'sehr wahrscheinlich manipuliert';
  }
  return {
    gesamtscore: Math.round(score * 1000) / 1000, prozent: Math.round(score * 100) + '%',
    bewertung: stufe(score),
    signale: { deepfakeGesicht: Math.round(deepfake * 100) + '%', kiGeneriert: Math.round(aiGen * 100) + '%' },
    quelle: imageData ? 'Upload' : 'URL',
    hinweis: 'Wahrscheinlichkeit, kein forensischer Beweis.'
  };
}
